INSERT INTO `categories` (`id`, `name`) VALUES (3, '2022 Zabıt Katipliği Metinleri') ON DUPLICATE KEY UPDATE `name`=`name`;
INSERT INTO `texts` (`category_id`, `title`, `content`) VALUES
(3, 'Metin 1', 'söz uçar yazı kalır atasözü her türlü iş haberleşme hizmet faaliyetinin kayıt altına alınmasının önemini ifade etmek için kullanılmaktadır kurumların veya kişilerin yaptıkları eylemleri somutlaştıran vesika olarak ifade edilebilecek olan belge bir işe yönelik oluşturulan yazılı kağıt veya dijital kayıtların tamamıdır hizmetler işlemler ve haberleşmeler esnasında ortaya çıkan yazılmış basılmış şifrelenmiş veya resmedilmiş kağıtlara belge denir belge aynı zamanda kişiler veya kurumlar arası sözsüz iletişimi sağlayan bir dokümandır varaka kelimesi arapça kökenli tek yaprak kağıt anlamına gelen kelimedir bu kelimenin çoğulu olan evrak kelimesi ise kağıtlar anlamına gelmektedir dolayısıyla yazılı kağıt olduğu ifade edilen belge kavramı yerine zaman zaman evrak ifadesinin kullanılabileceği bilinmelidir belge ve kayıt araçları ilk ortaya çıktığı günden bugüne bir hayli değişmiştir ilk dönemlerden günümüz teknolojisine gelene dek yazı ve kayıt araçlarında insan hayatını kolaylaştıran değişimler yaşanmıştır insanlar günlük hayatta birçok yazılı belgeyi okurlar iş yerinde ve özel hayatta sıklıkla yazılı belgelerle karşılaşılır bilgi vermek bilgi almak sözleşme yapmak rapor hazırlamak gibi birçok işte yazılı belgeler kullanılır bu belgeler dosyalanarak saklanabilir gerektiğinde yeniden ele alınarak incelenebilir birçok alanda yoğun bir şekilde belge kullanımı olduğu için hafızaya güvenerek işlerin yapılması düşünülemez haliyle insanların haklarını koruma ve güvence altına alma ihtiyacı belgelerin yazılı olmasını gerektirmiştir sözlü iletişimde unutulan düşünülmeyen durumlar olabilirken yazılı anlatımda kişi kendini düşünerek mantıklı ve gerektiği gibi ifade etmektedir isteği şikayeti duyurmak veya herhangi bir konuda bilgi vermek için resmi veya özel kurum ve kuruluşlara gerçek veya tüzel kişilere yazılan imzalı başvuru yazısıdır dilekçe beyaz kağıda yazışma kurallarına uygun bir şekilde yazılır dilekçede talepler kısa ve öz bir şekilde ifade edilir dilekçenin mavi tükenmez kalemle imzalanması gerekir gizli belgeler muhatabından başkasının okumaması ve görmemesi gereken hayati derecede önemli belgelerdir ağzı mühürlü ve kapalı zarfta gelen bu belgelerin gizlilik derecesi üzerinde belirtilir haliyle normal belgeye göre daha önce işleme alınan bu belgelerin kaydı da zarf üzerinde yapıldıktan sonra belge muhatabına ulaştırılır her aşamasında gizliliğe uyulan bu belgelerin dosyalanıp saklanması diğer belgelerden farklıdır'),
(3, 'Metin 2', 'devlet kurumlarında ve özel işletmelerde sürekli devam eden yazılı iletişimden kaynaklı belge dolaşımı vardır bir kuruma diğer kurumlardan veya kişilerden ulaşan belgeler gelen belge kapsamındadır gelen belgenin ilgili birime ulaştığı andan itibaren teslimi kontrolü ve sınıflandırması usulüne uygun olarak yapılır büyük kuruluşlarda bu işlemleri ayrı birim yaparken küçük kuruluşlarda bu görevi sekreter yapar gelen belgenin hangi işleme tabi tutulacağı belgenin nereden geldiğine hangi sıklıkla geldiğine bakılarak değerlendirilir kurum ve kuruluşlara belgeler posta aracılığıyla kurye eliyle faks kargo eposta ya da elektronik yolla gelebilir gelen belgenin sadece ilgili tarafından ve gerekiyorsa imza karşılığı alınması belgenin doğru kişi ya da birime ulaşmasında önemli bir husustur ifade edildiği gibi belge çeşitli yollarla iletilebilir belgenin insan eliyle iletilme sürecinde zaman ve maliyet kaybı yaşanırken elektronik ortamda belgenin gönderilmesi zaman ve maliyet kazancı sağlar ayrıca belgenin elektronik ortamda gönderilmesi kırtasiye işlerini ve bürokrasiyi azalttığı için hem süreç hızlanır hem de kağıt israfının önüne geçilmiş olunur kurumlarda ve işletmelerde gelen giden ve kurum içi süreklilik gösteren belge akışı olmaktadır belge akışı günümüze kadar çoğunlukla insanlar aracılığıyla yapılmaktaysa da şimdilerde yoğun şekilde elektronik ortamlarda yapılmaktadır zamanı etkili kullanmak ve verimliliği artırmak için işlem görmüş bir belgenin tekrar gözden geçirilmesine gerek yoktur bu yüzden eğer belgeyle ilgili gereken yapılmış ise belgenin dosyalanması isabetli olur işletmede belgenin tasnif ve ilgili işlemi yapma sürecinde zaman ve iş gücünden tasarruf sağlamak belirli ilkelere bağlı olarak çalışmayı gerektirir zamanı ekonomik kullanabilmek için iş yerinin ve çalışma masasının dağınık olmaması gerekir bunun için planlı çalışmak ve yapılacak iş süreçlerini belirleyip işleri zamanında yapıp bitirmek temel ilke olmalıdır çalışma ortamının dağınıklığının önüne geçmek için belge klasmanı yönteminden yararlanılabilir belge klasmanı yöntemi sayesinde dağınıklığa fırsat vermeden belgenin ilgili yere iletilmesi süreci hızlanır zaman yönetimi kurumun sağlıklı bir işleyişinin olması ve belge yükünün azaltılması bakımından çok önemlidir dosya ve belgelerin karışmaması için el altında hazır olması gerekenler başvuru anında bulunması gerekenler arşive gidecek belge ve dosyalar imha edilecekler olarak gruplara ayrılır 2 metin -- 1 of 1 --'),
(3, 'Metin 3', 'gelen belge defterine ayrıca gelen belgenin üzerine kaydedildiğine dair belge kayıt kaşesi basılır basılan kaşenin üzerine belgenin geldiği tarih gelen belge defterinden aldığı sıra numarası gideceği birim bilgileri veya ilgili kişi yazılır gönderilen kişiden kaydedilen belgeye cevap gelmesi halinde verilen cevabın tarihi ve giden belge defterinden aldığı çıkış sıra numarası yazılır ihtiyaç duyulduğunda belgeye ulaştığı saat yazılabilir acele ve önceliği olan belgeler bekletilmeden işleme alınır dergi broşür ve günlük gazete benzeri dokümanlar kaydedilmeden ilgili birime gönderilir faturalar belge kayıt defterine sıra numarası verilerek kaydedilir arkalarına kaşe basılarak ait olduğu birimin kodu belgenin sıra numarası ve geliş tarihi yazılır gelen belge birden fazla birimi ilgilendiriyorsa öncelikle ilk gönderim birinci derecede ilgili birime ulaştırılır diğer gönderimler ikinci ve üçüncü derecede ilgili birimlere gönderilir belgenin ulaştığı ilk birim kendisiyle ilgili işlemleri yaptıktan sonra belgeyi sırasıyla ikinci ve üçüncü ilgili birimlere gönderir bu şekilde belge ilgili bütün birimlerde işlem görmüş olur belge fotokopi ile gönderilecek birim sayısı kadar çoğaltılır belgenin aslının üzerine diğer nüshaların hangi birimlere gönderildiği fotokopilerin üzerine de belgenin aslının hangi birimde olduğu belirtilir yönetici onayından geçen belgeler ilgili teslim alma servisine gönderilir gelen belge kayıt defterine kaydedilir konularına göre zimmet edilerek ilgili servislere gönderilir belgenin birden fazla servisi ilgilendirdiği durumlarda belge konuyla ilgili ilk servise iletilir bu servis belgeyi diğer servislere gönderir belge birden fazla konuyla ilgiliyse birden fazla konunun dosyasına girebilir böyle durumlarda belge birinci derecede ilgili olduğu dosyaya yerleştirilir diğer dosyalara çapraz başvuru formu konur bu işlem sayesinde ilgili her dosyaya bakıldığında belge hakkında bilgi edinilir ve belgeye hızlıca ulaşılır yanlış gelen evrak açılmadan fark edilirse dağıtıcı ve kuryelere verilerek iade edilir belgenin yanlış geldiği açıldıktan sonra fark edilirse üst yazıyla çoğunlukla geldiği yere bazen gideceği yere gönderilir gelen evrak birimine gelen belgenin doğru olarak gelip gelmediği numaralarına imzalarına bakılarak kontrol edilir belge kontrol edildikten sonra zimmetli veya zimmetsiz olarak teslim alınır kurumlarda elden teslimi ve takip edilmesi gereken belgeler için zimmet defteri kullanılır'),
(3, 'Metin 4', 'kurumların birbirleri arasındaki belge akışından dolayı kuruma belge geldiği gibi kurumdan dışarı da belge gitmektedir kurum dışı kişi veya kurumlara belge gönderilmesi giden belge kavramını ortaya çıkarmıştır belge yönetimi gereğince giden belge çeşitli işlemlerden geçer giden belgeler giden belge defterine veya fişine kaydedilir haberleşme servisi gelen giden evrak servisi belge işleme bölümü gibi çeşitli adlandırmalar yapılan birimler vasıtasıyla gelen giden evrakla ilgili gerekli işlemler yapılır tasnif kayıt gözden geçirme dosyalama arşivleme gibi işlemler yapılır gerektiği durumlarda belge ilgili kişiye veya kuruma gönderilir giden belge sürecinde öncelikli olduğu ifade edilen belgeler hızlı bir şekilde hazırlanıp gerekli işlemler yapıldıktan sonra gönderilir bir belgenin öncelikli olduğunu içeriğine göre belgeyi hazırlayan kişi belirler gelen belgenin günlü veya süreli olduğu belirtilmiş ise belgeler süresi içinde cevaplandırılır hazırlanan belge giden evrak kayıt defterine kaydedilir evraka işlemine göre iki farklı yolla numara verilebilir elle oluşturulan giden evraklar taranarak programa kaydedilir verilen dosya numarası seçilir cevap verilecek bir yazı ise cevabı yazılarak amirin onayına gönderilir amir imzasıyla onaylayarak gelen yazı gönderilecek kişi kurum ya da servis seçilerek sistem aracılığıyla gönderilir bu şekilde giden evraka otomatik olarak sistem üzerinden sayı verilir kurum dışına gönderilecek belgeler bir yerde toplanır ve sınıflara ayrılır belgeler gidecekleri yere göre gruplara ayrıldıktan sonra gönderimleri yapılır bunun yanı sıra kurum içinde sistem üzerinden de gönderim yapılabilir evrakların dağıtım ve dolaşımı esnasında sorumlu bir yaklaşım ve emanete sahip çıkma bilinciyle hiçbir evrakın kaybolmasına fırsat vermeden ilgili kişinin özeli olan belgeye saygı duyarak belge ile ilgili gerekli işlemler yapılmalıdır belgenin zamanında ve doğru kişiye ulaşmasında gereken özen gösterilip bir mağduriyete sebep olunmamalıdır kurumlarda dosyalama ve arşivleme faaliyetlerinin yanı sıra evrak takibinin işlevsel bir şekilde yapılabilmesi için kayıt işlemleri yapılır evrak dolaşımıyla ilgili yeterli bilgi sahibi olmak gerektiğinde evraka ulaşabilmek için evrak kayıt işlemleri önemlidir bu amaçla kurumlarda giden evrak kayıt defterleri bulunur bu defterlerde giden belgeyle ilgili gerekli bilgiler yer alır kuruma belge gelmesinin yanında gelen belgelere cevap olarak gönderilen belgeler vardır'),
(3, 'Metin 5', 'dosyalama sisteminde ana unsur sistemin belli bir kurala uygun yürütülmesidir belli bir kuralı olmayan dosyalama sistemi karışıklığa neden olur dosyalama sistemi seçim süreci planlanırken ilk olarak kurumun ya da şirketin ihtiyaçlarını karşılayacak bir dosyalama sistemi seçilmeli ve dosyalama planı buna göre hazırlanmalıdır planlanan sistemde kayıtların ve belgelerin kaybolması ya da yanlış yerlere konması engellenerek hatasız bir şekilde süreç yürütülmelidir dosyalama sistemi seçim süreci ve planlamasında sistem az yer kaplamalı az malzeme kullanılmalı ve az çalışanla hatasız bir şekilde işlemelidir personel tarafından plan dışı keyfi dosyalar açılarak karışıklığa meydan verilmesi durumunda zaman geçtikçe evrak sayısı artacak ve buna bağlı olarak dosyalama sisteminde durum içinden çıkılmaz bir hal alacaktır hem saklanacak hem de atılacak belgeler planda belirtilmelidir belgeler kuruma başka kuruluştan gelen belgeler kurumun başka kuruluşa gönderdiği belgeler kurum içinde dolaşan belgeler olarak sınıflandırılır kuruma dışarıdan gelen belgeler işletme ile alakalı gerçek ve tüzel kişiliklerin kuruma yazılı şekilde veya elektronik ortamda gönderdikleri sözleşme fatura dilekçe resmi talimat teklifler raporlar gibi bilgi ve belgeleri içerir kurumun dışarıya gönderdiği belgeler kuruluşların kurum dışından yazılı veya elektronik ortamda gönderdikleri evraka cevap niteliğinde olan ya da başka kurumlara herhangi bir nedenle gönderdikleri belgelerden oluşur bu belgeler resmi belge dilekçe cevabı dilekçe rapor teklif gibi bilgi ve belgeleri içerir kurumun faaliyetleri sonucu ortaya çıkan kurum içi belgeler kuruluşların faaliyetleri sonucunda kurum içerisinde yapılan yazışmaları içerir diğer bir ifadeyle kurum içi belgeler de denir kurum içi belgeler aynı kurum içinde birimler arasında oluşan bilgi ve belgelerden oluşur insan kaynakları birimi ve muhasebe birimi arasındaki yazışmalar duyurular gibi bilgi ve belgeleri içerir dosyalanacak belgeler tasnif yapılarak dosyalanır tasnif sırasında belgenin ekleri belgenin sınıfı dosyalanacak klasörün uygunluğu kayıtların yapılması gibi kontroller yapılır yapılan bu kontrollerin ardından belge düzenli bir şekilde dosyalamaya hazır hale getirilir kullanılacak dosyalama sistemi sonrası dosya içeriğine bakılarak dosya bu şekilde açılmalıdır bir veya birden fazla evrak için elektronik ortamda ya da geleneksel yöntemle dosya açılabilir dosyada evrak araması için başlıklar kullanılır'),
(3, 'Metin 6', 'kurum ve kuruluşlarda üretilen belgelerin korunması da en az belge yönetiminin diğer unsurları kadar önemlidir belgelerin uzun zaman boyunca zarar görmeden korunmasının yanı sıra kurumsal ve belgelenebilecek yapıya uygun bir saklama planının tasarlanması gerekir dosyalar öncelikle güneş ışınları rutubet yangın ve su baskınları gibi tehlikelerden korunmalıdır belgelerin fiziksel özelliğini bozan bazı zararlı etkilerin de mümkün olduğunca azaltılması gerekir bunlar kağıt içindeki asit miktarı bakteri toz haşere gibi zararlı etkenlerden kaynaklanır ayrıca gizli ve önemli belgelerin tahrip olmasının çalınmasının veya kopyalanmasının önüne geçilmesi de son derece önemlidir bu tür belgeler gerekli görüldüğü takdirde ayrı ve güvenli bir yerde tutulmalıdır belgeleri korumanın üç önemli nedeni vardır bunlar belgeleri bilgi kaybına neden olacak her türlü tahrip edici unsura karşı korumak belgelerin kaybolmasını önlemek belgelerin ilk haldeki gibi asli düzenlerinin bozulmasını engellemek şeklinde sıralanabilir işaret edilen bu nedenler belgelerin hem fizik- sel olarak korunmaları hem de belgelere erişimin doğru eksiksiz ve hızlı sağlanması ile ilişkilidir kurum ve kuruluşlarda belge yönetiminin son aşaması arşiv çalışmalarıdır kurumların faaliyetlerinin sonucunda ortaya çıkan ve çeşitli kullanım alanları olan belgeler belirli bir süre saklandıktan sonra arşivlerde muhafaza edilir bu bağlamda arşivler kurum ve kuruluşların bilgi depolarıdır arşiv malzemesinin uzun süre güvenli bir ortamda sağlam bir şekilde muhafaza edilebilmesi için arşivleme araçlarına ihtiyaç duyulur arşiv malzemelerinin ne tür kaplarda saklanacağı bunları yerleştirecek raflar dosya dolabı imha makinesi gibi arşivleme araçları da en az arşiv araçları kadar önem taşır plastik veya karton malzemelerden üretilen kutuların içerisine arşivlenecek malzemeler belirli bir düzene göre yerleştirilir arşivlenecek malzemenin dağılmadan toplu bir şekilde saklanması sağlanır arşiv kutularının içerisine koyulan arşiv malzemelerinin içeriği hakkında kutunun dışına bilgiler yazılır arşiv süresi kısa olan ve bir süre sonra imha edilmesi planlanan arşiv aletlerinin istifinde arşiv kutuları tercih edilir bu kutuların sık sık hareket etmesi zarar vereceğinden kalıcı bir şekilde istifine özen gösterilir arşiv malzemesi saklama kutusu ucuzdur hiçbir metal ve kimyasal madde olmadan katlama usulü yapılır arşiv malzemesi bırakıp tekrar rahatça çıkarılabilecek şekilde kapatılır'),
(3, 'Metin 7', 'hak kavramı hukukla ilgili temel kavramlardan biridir adalet ve hukuka uygunluk anlamlarına gelen hak kelimesi arapça hukuk kelimesinin tekil halidir verilmiş bir emekten dolayı maddi ve manevi yetkidir hak yasalar ve anlaşmaların insana tanıdığı yetkilerin toplamıdır kişiler haklarını kullanıp kullanmama iradesine sahiptirler bir hakkın kullanımı ise medeni kanunda belirtildiği üzere dürüstlük ilkesi dahilinde olmalıdır hak sahipleri özel veya tüzel kişiler olabilir sağ olarak doğmak koşuluyla ana rahmine ilk düştüğü andan itibaren insanlar hak ehliyetini kazanırlar haklar kanunlarla düzenlenerek koruma altına alınırlar haklar aslında hukuk kurallarına dayanır toplum içinde yaşayan herkesin üstlenmesi gereken belli başlı rolleri bulunur aynı zamanda devletler ve uluslararası kuruluşlar tarafından güvence altına alınan haklar da bulunmaktadır din ve vicdan hürriyeti düşünce hürriyeti özel hayatın gizliliği hakkı sahip olduğumuz haklardandır kişilerin hukuk düzeni tarafından korunan menfaatlerini ifade eden hak kavramı hukuk kavramı ile birleşiktir bilimsel bir disiplin sistemi olarak hukuk kişiler arası ilişkileri kişiler ile devlet veya devleti oluşturan kurumlar arası ilişkileri ve devlet ile devletler arası ilişkileri düzenleyen kurallar bütünüdür hukuk kişilere yetki verebileceği gibi yaptırım da uygulayabilir ceza yaptırımı yasaya ve kurala aykırı davranılması halinde hukuk düzenince öngörülen sonuçtur yaptırımın amacı ise kişilerin hukuka uygun davranmasını sağlamak ve toplumsal düzene aykırı davranışın meydana getirdiği olumsuz sonuçları önlemektir örneğin trafikte kırmızı ışıkta durması gereken bir aracın yoluna devam etmesi halinde aracı kullanan kişiye ve araç sahibine trafik cezası yaptırımı uygulanması borcunu zamanında ödemeyen kişinin malına hukuki yollarla el konularak alacaklıya hakkın verilmesi bir mala zarar veren kişiye bu malın değerinin ödettirilmesi gibi hukuk sisteminin en önemli özelliği yasaların açık anlaşılır ve kesin olmasıdır yazının icat edilmesinden sonra bütün yasalar yazılı hale getirilmiştir yasal kurallar sistemli şekilde toplanmış açıklık ve kesinlik kazanarak kolayca başvurulacak kaynak haline getirilmiştir hukuk gelişirken birtakım esaslar üzerinde durulur bütün hukuk kurallarının amacı kendine yapılmasını istemediğin bir şeyi başkasına da yapmamak üzerine kuruludur zaten insanlar huzur ve güven içinde yaşamak için hukuka ihtiyaç duymuşlardır ve hukuk herkes için vardır'),
(3, 'Metin 8', 'ayırt etme gücüne sahip ve ergin olup kısıtlı olmayan kişiler tam ehliyetliler grubuna girer tam ehliyetliler hiçbir izne gerek olmaksızın kendi iradeleriyle hukuki işlemleri gerçekleştirebilirler borç altına girebilirler yaptıkları hukuka aykırı hareketlerden de sorumlu olacaklardır kendi haklarını korumak için dava açabilirler ayırt etme gücüne sahip olmayan herkes tam ehliyetsizdir ayırt etme gücüne sahip olmayan kişinin kısıtlı olup olmadığına veya ergin olup olmadığına bakılmaksızın tam ehliyetsiz olduğu söylenebilir doğruyla yanlışı ayırt edebilecek zeka seviyesine sahip olmayan kişilere üç yaşındaki çocuk veya elli yaşındaki akıl hastası örnek olarak verilebilir tam ehliyetsizler fiil ehliyetine sahip değillerdir tam ehliyetsiz kişiler ayırt etme gücüne sahip olmadıklarından dolayı evlenemezler ayrıca tam ehliyetsizler hukuki işlem yapamazlar bu yaptıkları hukuki işlem geçersiz sayılır bu kişilerin hukuki işlemlerini anne babası veya ayırt etme gücü olmayanlara hukuki işlemlerde onları temsil etmek ve menfaatlerini korumak için mahkeme tarafından atanan yasal temsilciler yürütür ancak mahkemece atanan vasiler tam ehliyetsiz kişiler adına bazı hukuki işlemleri yapamazlar bu işlemlere örnek vermek gerekirse kefil olmak vakıf kurmak ve bağış yapmaktır tam ehliyetsiz sayılan akıl hastaları başkalarının malına verdiği zarardan sorumlu olmazlar yaptıklarından dolayı bu kişilere ceza verilemez ancak akıl hastalarının kusursuz sorumluluğu söz konusu olabilir yani başkalarının malına zarar veren akıl hastasının ekonomik durumunun iyi olması halinde mahkeme tarafından sebep olduğu zararları ödemesine hükmedilebilir ancak ceza verilemez normalde tam ehliyetliler bazen dış etkenlerle tam ehliyetsiz hale gelebilir buna sarhoşluk örnek verilebilir kişi sarhoşken ayırt etme gücüne sahip olmayacağından dolayı tam ehliyetsizdir iradeleriyle sarhoş olan kişiler ayırt etme gücüne sahip olmasalar bile yaptıkları hukuka aykırı eylemlerden dolayı sorumludurlar örneğin kişi kendi iradesiyle sarhoş olup başkasının arabasına zarar vermesi halinde hem ceza almak hem de verdiği zararın karşılığını ödemek zorunda kalır kişi kendi iradesi dışında sarhoş olduğunu ispatlarsa ceza yaptırımı uygulanmaz sınırlı ehliyetli tam ehliyetli şartlarını taşıdığı halde ehliyeti sınırlanan kimsedir ayırt etme gücüne sahip ve ergin olup kısıtlı olmayan kişiler yani tam ehliyetli şartlarını taşıyıp da kendilerine yasal danışman atanan kişilerdir'),
(3, 'Metin 9', 'sözleşme hukuki sonuç doğurmak amacıyla iki ya da daha çok kişinin kuruluşun karşılıklı ve birbirine uygun irade beyanıyla gerçekleşen işlemdir bir sözleşme yapma niyetinde olan kişinin bazı hususları göz önüne alması gerekir sözleşme hazırlanırken dikkat edilmesi gereken en önemli husus sözleşmenin tarafların isteklerini tam olarak yansıtması ve mümkün olduğu ölçüde ileride taraflar arasında uyuşmazlığa yer vermeyecek biçimde kaleme alınmasıdır ayrıca sözleşme uyuşmazlık çıktığı durumda da taraflar arasındaki uyuşmazlığı gidermeye ve en aza indirmeye yönelik hükümleri kapsamalıdır bir sözleşmenin yapılması için öncelikle o sözleşmeyi yapmak isteyen kişilerin karşılıklı olarak sözleşme yapma iradesini ortaya koymaları gerekir taraflar bu iradeyi fiilen bir araya gelerek ortaya koyabilecekleri gibi farklı yollarla da ifade edebilirler örneğin iki farklı şehirde bulunan taraflar noter aracılığı ile sözleşme yapabilirler tarafların karşılıklı istek ve iradelerini beyan ettikleri bu aşamada dikkat edilmesi gereken husus tarafların bireysel olarak sözleşme yapmakla ne istediklerini ve hangi amaçla o sözleşmeyi yaptıklarını bilmeleridir bundan başka tarafların sözleşmeye ilişkin istek ve amaçlarının birbiriyle uyumlu olması yani iradelerin aynı amaca yönelik olması gerekir tarafların sözleşmenin ilgili olan hukuk dalını saptamak ve eğer mevcutsa sözleşmeyi doğrudan veya dolaylı olarak etkileyen hukuki mevzuatları yargı kararlarını bulma ve genel olarak sözleşmenin hukuki sınırını belirlemeleri gerekir taraflar sözleşmeyi bir bütün olarak ele alıp incelemeli ve bir taslak hazırlamalıdır sözleşme özgürlüğü kişilerin diledikleri sözleşmeyi geçerli yapma hususunda sahip oldukları özgürlük olarak tanımlanır mevzuatta sözleşme özgürlüğü ilkesinin bir gereği olarak şekil serbestisi ilkesi geçerlidir borçlar kanununun ilgili hükmünde akdin sıhhati kanunda açık bir husus olmadıkça hiçbir şekle tabi değildir şeklinde yer alarak bu ilke açıkça belirtilmiştir yargılama usulüne ilişkin kanuna göre bir hakkın doğması düşmesi devri değişimi ikrarı edimi ve itfası amacıyla yapılan hukuki işlemlerin yapıldıkları zamanki miktar ya da değeri belirli bir miktarı geçtiği takdirde senetle ispat olunması gerekir bu sebeple sözleşme taraflarının aralarında herhangi bir hukuki uyuşmazlık çıkması halinde ispat kolaylığı sağlamak ve tarafların hak kaybına uğramasını engellemek için sözleşmelerin yazılı bir şekilde yapılması daha uygun olur'),
(3, 'Metin 10', 'kıymetli evrak günümüzde başta kredi kartları ve banka kartları ile elektronik para ve ödeme araçlarının yaygın olarak kullanılmasına rağmen teminat ve kredi işlevinin olması sebebiyle ticari hayatta yaygın olarak kullanılmaya devam etmektedir türk ticaret kanunu bölümlerinden birini de kıymetli evrak hukuku oluşturmaktadır türk ticaret kanunu haricinde diğer hukuk kaynaklarında da kıymetli evraka ilişkin hükümler yer almaktadır kıymetli evrak türk ticaret kanununun ilgili maddesinde kıymetli evrak öyle senetlerdir ki bunların içerdikleri hak senetten ayrı olarak ileri sürülemediği gibi başkalarına da devredilemez şeklinde tanımlanmıştır buradan anlaşıldığı gibi kıymetli evrakın hak senet ve hak ile senet arasındaki bağlantı olmak üzere üç temel unsuru bulunmaktadır kıymetli evrak senettir ancak her senet kıymetli evrak değildir senet kişinin kendisi aleyhine düzenlediği irade açıklaması içeren yazılı belgedir yazılı olması elle yazılması anlamına gelmemektedir elektronik imza kanununun ilgili maddesi uyarınca güvenli elektronik imza elle atılan imzayla aynı hukuki sonuçları doğurur ancak bu durumun da istisnaları bulunmaktadır kıymetli evrak türleri arasında yer alan kambiyo senetleri kanun hükümleri uyarınca elektronik imzayla düzenlenemez ıslak imzalı olarak tükenmez veya dolma kalemle imzalanmalıdır kıymetli evraklar özel hukuka ilişkin ekonomik değeri olan ve devredilebilen özelliklerde haklar içerir bu özellikleri içermeyen senetler kıymetli evrak vasfını yitirmiş olur kıymetli evrak senetten ayrı ileri sürülemez ve senetten ayrı başkasına devredilemez kıymetli evrak borçlusu ancak senedin teslimi karşılığında borcunu ödeme ile yükümlüdür kıymetli evraktaki hakkı talep eden senedi ibraz ettiğinde borçlu da borcunu kıymetli evrakı ibraz eden meşru hamile ifa etmek zorundadır kıymetli evrakta en temel özellik tedavül fonksiyonudur kıymetli evrak temsil ettiği hakkın el değiştirmesi ve devredilmesi için düzenlenir gerek tedavül fonksiyonu gerek kanundaki düzenleniş tarzı dikkate alındığında kıymetli evrakın devir şekli açısından sınıflandırılması büyük önem taşır kıymetli evrak devir açısından nama emre ve hamile olmak üzere üç şekilde düzenlenebilir bunun dışında kıymetli evrakın devir açısından düzenlenmesi mümkün değildir örneğin kambiyo senetlerinden olan poliçe yazılı kıymetli evrak çeşitlerindendir nama yazılı kıymetli evrakta hak sahibinin ismi yer aldığından dolayı değiştirme kabiliyeti çok azdır'),
(3, 'Metin 11', 'bilgi akışını sağlayan yazılı sesli veya görsel araçlara kitle iletişim araçları denir bu akış bireyden çoğula veya çoğuldan bireye doğrudur kitle iletişim araçlarının belirleyici özelliği bir mesajı aynı anda çok sayıda kişiye ulaştırmasıdır ülkemizde sıklıkla kullanılan kitle iletişim araçlarının başında televizyon gelir televizyonun hemen hemen herkesin evinde bulunması ücretsiz olması ve her kitleye hitap etmesi bunun ana nedenleri arasındadır her- hangi bir toplumsal sorunun çözümünde toplumun geneline ulaşmak onları mevcut sorun hakkında yüz yüze bilgilendirmek oldukça zordur ancak kitle iletişim araçlarını kullanarak çok sayıda insana ulaşmak onları bilgilendirmek ve onların görüşlerini almak daha kolaydır kitle iletişim araçları bu kolaylığının yanı sıra kitleyi olumsuz etkileme ve yönlendirme gibi özelliklere de sahiptir kitle iletişim araçları yapısal özellikleri nedeniyle farklı kitleler tarafından tercih edilmektedir örneğin gazete tek başına ve tüketicinin genel veya özel düşünceleri duyguları ve davranışlarında ölçü olarak değerlendirdiği gruplara danışılmadan hızlı okunan kitle iletişim aracıdır gazete günlük haberleri gelişmeleri öğrenmek için alınır gazetenin bir kere okunması yeterlidir ancak anlaşılmayan konular olunca tekrar okuma şansı vardır dergi evlerde iş yerlerinde bir haftadan daha uzun süre durabilir dergi birkaç kere okunabilir çünkü dergide yazılanlar defalarca okunabilir ve referans gruplarıyla tartışılabilir dergiler özellikle belli konularda ayrıntılı araştırmaları içerdiği için başvuru aracı olarak kullanılabilir radyo ise gazete ve dergiden çok daha farklı bir kitle iletişim aracıdır radyoda sade açık ve tekrarlanan bir metin ses yoluyla kitleye ulaştırılır metnin içeriği ve ses tonlaması gibi özellikler kitle üzerinde etkili rol oynar ama sesli iletilerin hızlı unutulma riskleri vardır televizyonda hareketli görüntü ve ses vardır ancak televizyon görüntüsü yanılsamadır gerçekte görüntü yoktur küçük noktaların yoğunluklarıyla oluşan resim insan zihninde önceden tanımlanan bilgilerle çakıştırılır ve bu bilgiler algılanıp anlam kazanır yarım görüntülerin diğer yarısını zihin tamamlar zihin mekanik olarak çalışır ancak gazete okurken olduğu gibi kod çözmeyle uğraşmaz eskiden izleyicinin anında çözümleme yapması gerekirdi fakat yeni teknoloji ile artık televizyon yayınları internet üzerinden izlenip kayıt ediliyor ve elektronik posta gibi yollarla geri bildirim imkanı sağlanıyor'),
(3, 'Metin 12', 'kamu gücüne ve otoritesine sahip olan çeşitli devlet kurumları ve kuruluşların bu otoriteye tabi kişilerle veya birbirleriyle olan ilişkilerini düzenleyen hukuk kurallarına kamu hukuku denir insanların ve insanların oluşturduğu toplulukların eşit şarta ve yetkilere tabi özgür kimseler olarak kendi aralarındaki ilişkileri düzenleyen hukuk kuralları ise özel hukuk olarak tanımlanmaktadır kamu hukukunun en temel niteliği bu hukuk alanına giren ilişkilerde tarafların eşit olmaması kamu yararının temsilcisi konumundaki devletin ve diğer kamu tüzel kişilerinin üstün konumda bulunmasıdır bu konumları onlara tek taraflı olarak ilişkinin kapsamını ve içeriğini belirleme imkanı vermektedir özel hukuku karma hukuk ve kamu hukukundan ayrıştıran en önemli özellik bu alandaki hukuk ilişkilerinin eşitlik ve irade serbestisi ilkesine dayanmasıdır hukukta asıl olan bireylerin özgürlüklerinin ve haklarının güvence altına alınmasıdır kamu hukuku özel hukukun hizmetinde ve onun üzerinde koruyucu olmalıdır tarihsel açıdan bakıldığında anayasa hukuku idare hukuku ve ceza hukukunun da birey hak ve özgürlüklerini korumak üzere geliştirildikleri görülmektedir anayasal metinler yöneticilerin siviller üzerindeki baskılarını sınırlandırma bunu en aza indirme mücadelelerinin sonucudur aslında kamu hukukunun da karma hukukun ve özel hukukun da asıl gayesi birey hak ve özgürlüklerini korumaktır günümüzde özel hukuk ve kamu hukuku bundan dolayı gittikçe birbirine daha çok yaklaşmaktadır fakat bu açıdan bakılsa da gerek kamu hukukunun gerekse karma hukukun ve bunların alt dallarının özel hukuktan ayrılmış başlı başına birer hukuk dalı olduğu görülmektedir kişilerin birbirleriyle olan ilişkilerini eşitlik ve irade serbestisi ilkesi doğrultusunda düzenleyen özel hukuk kuralları konuları ve özellikleri itibarıyla birbirinden oldukça farklıdır yıllar içerisinde toplumsal hayatta iletişimde teknolojide meydana gelen değişimler birçok yeni hukuki problemleri de beraberinde getirmiştir bu karmaşık hukuk ilişkilerini sadece özel hukuk olarak tanımlamak yetersiz kalmaya başlamıştır özel hukuk bir üst kavram olarak kalması şartıyla kendi içinde çeşitli dallara ayrılmıştır örneğin daha öncesinde medeni hukukun parçası olan borçlar hukuku şimdilerde başlı başına hukukun dalı haline gelmiştir önceden özel hukuk içinde sayılan fikir hukuku artık karma hukuk içinde sayılmaktadır özel hukukun alt dalları farklı kaynaklarda farklı şekilde sayılabilmektedir'),
(3, 'Metin 13', 'kamu hukuku devletin gerçek veya tüzel kişilerle ya da başka devletlerle olan hukuki ilişkilerini düzenleyen hukuk dalıdır ancak taraflardan birinin devlet olması her hukuki uyuşmazlığın kamu hukukunun alanına gireceği anlamını doğurmaz taraflardan birinin devlet diğerinin özel kişiler olduğu bazı hukuki ilişkiler özel hukuk veya karma hukuk çerçevesinde değerlendirilmektedir burada dikkat edilmesi gereken konu devletin hangi sıfatla katılmakta olduğudur devlet bu ilişkiye üstün otoritenin yani kamu iktidarının sahibi olarak katılıyor ve bu sebeple ilişkinin tarafları arasında eşitlik değil altlık üstlük durumu görülüyorsa bu ilişkiyi düzenleyen hukuk kuralları kamu hukuku kurallarıdır genel hukukta olduğu gibi kamu hukuku da yazılı ve yazısız bağlayıcı yardımcı kaynaklara dayanmaktadır kıta avrupası hukuk sisteminde asıl olan hukuk kurallarının yazılı olmasıdır bu sistemi benimsemiş olan ülkemizde hukuk kurallarının büyük çoğunluğu yazılı hukuk kuralları şeklindedir herhangi bir yetkili makam veya kurul tarafından konulmuş sürekli genel ve soyut hükümlerdir anayasa uluslararası anlaşmalar kanunlar kararnameler yönetmelikler bu gruba girer ayrıca bir kanun koyucu tarafından çıkarılmamış ise de içtihadı birleştirme kararları da bu gruba girmektedir yazılı kaynaklarda bir hiyerarşi vardır bu hiyerarşiye normlar hiyerarşisi adı verilmektedir çok eski zamanlardan beri sürekli tekrar eden herhangi bir makam tarafından konulmayan kendiliğinden oluşan toplum vicdanında yer eden kurallardır bu kurallara uymanın zorunlu olduğu yönünde toplumda genel bir kanaat oluşmuştur hukuk düzeni tarafından tanınan ve desteklenen bu türden kurallara da yazısız kaynaklar denilmektedir örf ve adetler bu gruba girmektedir mahkemelerin karar verirken uymak zorunda olmadığı ancak o uyuşmazlık çözümünde önemli rol oynayacak kaynaklardır uyuşmazlık çözümü için yazılı kaynaklar yeterli ise yardımcı kaynaklara başvurulmaz türk hukuk sistemine göre hakim önüne gelen davayı çözmekle yükümlüdür ancak hızla değişen dünyada kanunlar gelişmelerin gerisinde kalabilmektedir bu nedenle yeni ortaya çıkacak problemleri düzenleyen kanuni düzenlemeler yapılamamış olabilmektedir bu gibi durumlarda hakim yine de bir karar vermek zorundadır dava sürecinde önce yazılı hukuk kuralı uygulanır yazılı hukuk kuralının olmaması halinde hakime hukuk yaratma yetkisi tanınmıştır hem yazılı kanunlarda hem örf ve adet hukukunda bulunmayan konu hakimin takdirindedir'),
(3, 'Metin 14', 'hukukta önemli olgulardan biri hak sahibi olmak olup bunu ispat ederek ortaya çıkarabilmek aynı derecede önemlidir gerçekte hak sahibi olan birçok kişinin ispat kurallarına dikkat etmemesinden kaynaklı hakkını ispat edemediği bunun sonucunda mağdur olduğu çok fazla örnek bulunmaktadır dolasıyla hak kazanılırken ve kullanılırken ileride durumun nasıl ispat edileceği düşünülmelidir bir hukuki uyuşmazlıkta taraflar her türlü delille hakkını ispat edebilir medeni kanun bu ispat araçlarından resmi belgelere özel bir önem yüklemiştir medeni kanunun ilgili maddesinde kanunda aksine bir hüküm bulunmadıkça taraflardan her biri hakkını dayandırdıkları olguların varlığını ispatla yükümlüdür ifadesi ile iddia edenin ispat etmekle yükümlü olduğu belirtilmiştir bir kişi birisinden alacağı olduğunu iddia ediyorsa bu durumu kişinin ispat etmesi gerekmektedir borçlunun borçlu olmadığını ispat etmesi gerekmez hukuken haklı olduğunu savunan ve tartışma başlatan taraf hakkının dayandığı olayları olguları ispat etmek zorundadır buna karşın diğer taraf da karşı ispat hakkını kullanmakta serbesttir burada önemli olan tartışmayı başlatanın yani haklı olduğunu iddia edenin ispatla yükümlü olmasıdır örneğin evlilik birliğinin temelinden sarsılması iddiasıyla dava açan yani hukuken tartışmayı başlatan davacı eş bu evliliğin ne şekilde sarsıldığını ispat etmek zorundadır diğer eşin evliliğin sarsılmadığını ispat etme yükümlülüğü bulunmamaktadır ancak taraflar kendi iddialarını ispat etme hakkına sahiptir toplum yaşamının daha rahat ve güvenli hale gelmesi hukuk kurallarıyla oldukça ilgilidir bunun için kanunlar bazı kurallara istisnalar getirerek insanların hukuki ilişkilerini kolaylaştırmak ister ispat yüküyle ilgili kural iddia edenin ispat etmesi olduğu halde bazı durumlarda kanun olağan genel doğruları öncül olarak hukuken doğru olarak varsaymaktadır hukuken doğruluğu kabul edilen bu türden varsayımlara karine denir örneğin medeni kanuna göre yaşının küçüklüğü nedeniyle akıl hastalığı akıl zayıflığı sarhoşluk ya da bunlara benzer sebeplerden biriyle akla uygun biçimde davranma yeteneğinden yoksun olmayan herkes kanuna göre ayırt etme gücüne sahiptir buna göre medeni kanunda sıralanan durumların dışında kalan herkesin ayırt etme gücüne sahip olduğu karinesi benimsenmiştir dolayısıyla birinin ayırt etme gücünün olmadığını düşünen kişi bunu ispat etmelidir resmi sicil veya senetler belgeledikleri olguların doğruluğuna kanıt oluşturur'),
(3, 'Metin 15', 'dünya üzerinde gerçekleşen bütün olumlu gelişmeler yalnızca insanın varlığının devam etmesine yönelik etkilere sahiptir günümüzde meydana gelen gelişmelerin yeniliklerin en önemli etkisi bu unsurların insanın kişiliğini geliştirmeye hizmet etmesi ve kişiliğini korumasıdır hukukta kişi hak ve borçlara sahip olabilen varlıktır kişilik kavramı ise dar anlamda ve geniş anlamda olmak üzere iki farklı şekilde tanımlanmaktadır dar anlamda kişilik ile kişi kavramı eş anlamlıdır geniş anlamda kişilik hak ehliyetini fiil ehliyetini kişilik haklarını ve kişisel hal sicillerini kapsamaktadır kişisel haller kişinin kendine özgü bulunan onu diğer insanlardan ayıran nitelikleridir örneğin kişinin erginliği medeni durumu cinsiyeti gibi unsurlar kişisel haller arasında bulunan ve hukuk düzeni tarafından dikkate alınan niteliklerdir kişinin insan onuruna yaraşır bir hayat sürdürebilmesinin olmazsa olmaz şartı onun maddi manevi ve ekonomik bütünlüğü ile kendi varlıkları üzerinde sahip olduğu mutlak haktır kişilik hakkı parayla ölçülemeyen vazgeçilemeyen başkasına devredilmeyen ve mirasçılara geçmeyen bir haktır örneğin bir kişinin şeref ve haysiyeti özgürlüğü aile içi sırları fikri faaliyetleri adı şöhreti gibi unsurlar kişilik hakkı kapsamında olup başkalarına devredilemez niteliktedir kişilik haklarının vazgeçilemez ve devredilemez haklar olduğu medeni kanunun ilgili maddesinde kimse hak ve fiil ehliyetlerinden kısmen de olsa vazgeçemez kimse özgürlüklerinden vazgeçemez veya onları hukuka ya da ahlaka aykırı olarak sınırlayamaz ifadesi ile kesin olarak belirtilmiştir bahsi geçen maddede kişilik haklarının devredilemez nitelikte olduğu vurgulanmış ise de hangi unsurların kişilik hakkı içerisinde yer aldığı açık bir şekilde belirtilmemiştir bu unsurların belirtilmemesinin sebebi insan varlığını oluşturan ve insanın sırf insan olduğu için sahip olduğu değerleri bir bütün olarak belirtmenin zor olmasıdır bir diğer sebep ise sınırsız sayıda olan kişilik haklarının kanun ile sınırlandırılmasının kişilik haklarına doğrudan zarar verecek bir durum olmasıdır hukukta kişilik hakları konusunda sınırlı sayı ilkesi geçerli değildir medeni kanunda sayılmamış ise de hukuk bilimciler kişilik haklarını maddi haklar manevi haklar mesleki haklar ekonomik haklar gibi farklı kategorilerde incelemektedir maddi haklar kişinin vücut bütünlüğüne yönelik hakları iken manevi haklar kişinin onuru ve saygınlığına yönelik hakları arasında yer almaktadır'),
(3, 'Metin 16', 'modern hukuk sistemlerinin çoğunda olduğu üzere hukuk sistemimizde hak sahibi kişiler sadece fiziki varlığı bulunan bireyler değildir fiziki varlığı olmayan ancak hak sahipliği kazanmış topluluklar veya kurumlar bulunur hukuk düzeni tarafından kendilerine kişilik verilmiş ve tek sayılan oluşumlara tüzel kişi denir başka deyişle belli amacı gerçekleştirmek üzere bağımsız bir varlık halinde teşkilatlanmış haklara borçlara sahip olma yeteneği hukuk düzenince tanınmış mal topluluklarıdır tüzel kişilerin ortak amaca sahip kişiler veya mal topluluklar etrafında birleşen kişilerden malı tahsis eden kişilerden bağımsız kişiliği vardır ancak tüzel kişiliğin hukuken kişi olarak kabul edilebilmesi için üç unsurun bir arada olması gerekir tüzel kişiliğin bağımsız kişi olarak var olmasının ilk unsuru örgütlenmedir örgütlenmeden kasıt kurulması düşünülen tüzel kişilik için kanunen zorunlu olan organların oluşumuyla gerçekleşen bir unsurdur sürekli olarak örgütlenmemiş şahıs veya mal topluluklarına hukuk düzenince tüzel kişilik tanınmaz tüzel kişilik oluşumunun tamamlanması için gerekli olan diğer unsur kuruluş belgesinde yer alan sürekli amaçtır belirlenen amacı gerçekleştirmek üzere toplanan kişiler veya mal topluluklarında bireylerin kişisel çıkarlarının üzerinde olan genel ve ortak çıkarın olması gerekir tüzel kişilerde oluşan çıkar manevi parasal veya bilimsel çıkar olabilir burada önemli olan tüzel kişiliğin ortak çıkarının sürekli olmasıdır bu sebeple geçici amaca yönelik toplanan kişi veya mal topluluklarına tüzel kişilik denilmez tüzel kişiliğin oluşumunda gerekli unsur tüzel kişiliğin hukuk düzenince tanınmasıdır hukuk düzeni tarafından kişi veya mal topluluğuna tüzel kişilik verildiğinde kişi veya mal topluluğu bağımsız varlık haline gelir tüzel kişilik biyolojik kişilikten farklıdır biyolojik kişiliğin başlangıcı sağ olarak doğum anıdır ancak tüzel kişiliğin gerçekleştiği zamana doğum gibi bir özelliği yüklenemez bu yüzden tüzel kişiliğin kişilik kazanma anı devlet tarafından belirlenir ülkemizde tüzel kişiliğin kişilik kazanma anını belirlemek amacıyla serbest kuruluş sistemi izin sistemi tescil sistemi olmak üzere üç farklı sistem kabul edilmiştir izin sistemine göre kişi veya mal topluluklarının tüzel kişilik kazanmaları devletin iznine bağlıdır örneğin türk ticaret kanununa göre anonim şirketlerin kurulması için ticaret bakanlığından izin alınmalıdır kurulma anını düzenleyen ikinci sistem tescil sistemidir'),
(3, 'Metin 17', 'normatif sistem olarak da geçen tescil sistemine göre tüzel kişiliğin kişilik kazanma anı tüzel kişinin kurulması için gerekli olan koşulun yetkili makam tarafından incelenme sonrasıdır yetkili makam tarafından yapılan inceleme sonucunda kuruluş şartlarının yerine getirildiğinin tespit edilmesi halinde tüzel kişiliğe izin çıkar örneğin türk hukukuna göre vakıflar tescil sistemi ile kurulur tüzel kişiliği kurmak isteyen kişilerin herhangi yetkili bir makamdan izin almasına gerek olmayan sistem ise serbest kuruluş sistemi olarak anılır bu sistemde tüzel kişiliğin kazanılması için gerekli olan koşullar mevzuat tarafından daha önceden belirlenmiştir mevzuat tarafından belirlenmiş olan koşulların yerine getirilip getirilmediği herhangi bir makam kontrolünden geçmez bu sebeple serbest kuruluş sisteminde mevzuat tarafından belirlenmiş koşullar yerine getirildiği anda tüzel kişilik kazanılmış olur örneğin siyasi partiler sendikalar ve dernekler serbest kuruluş esasına dayanır tüzel kişiliğin kazanılma anı kadar tüzel kişiliğin sona erme anı da önemlidir çünkü tüzel kişiliğin fiil ehliyetinin veya hak ehliyetinin sona ermesi ancak tüzel kişiliğin son bulmasıyla mümkündür tüzel kişiliğin sonlanması tüzel kişiliğin sona erme nedenlerine göre belirlenir medeni kanunun diğer kanunların ilgili hükümlerine göre tüzel kişiliğin sonlanması üç şekilde olmaktadır bunlar kendiliğinden sona erme bir iradeyle sona erme mahkeme kararıyla sona ermedir tüzel kişiliğin kanun veya kuruluş işleminde mevcut belirli nedenlerin gerçekleşmesi sonucu başka işlem veya karara gerek olmadan kanun gereği sona ermesi durumunda tüzel kişilik kendiliğinden sona ermiş kabul edilir infisah veya dağılma olarak ifade edilen durum genellikle tüzel kişiliğin amacını gerçekleştirmesi veya tüzel kişiliğin amacını gerçekleştirmesinin imkansız hale gelmesi durumunda gerçekleşir örneğin belirli süre için kurulmuş tüzel kişiler sürenin dolmasıyla kendiliğinden sona erer tüzel kişiliğin sona erme sebeplerinden diğeriyse fesihtir tüzel kişiliğin iradeyle sona ermesi durumuna örnek olan sona erme sebebinde tüzel kişilik yetkili organ veya mahkeme kararı ile sona erebilir yetkili organlardan kasıt ilgili tüzel kişilerin bu konuda karar almaya yetkili organıdır tüzel kişiliği sona erdiren sebeplerden sonuncusu ise mahkeme tarafından verilen karardır kanunda sayılan belirli bir nedenin ortaya çıkmasıyla tüzel kişilik mahkeme kararına dayanılarak sona erdirilebilir'),
(3, 'Metin 18', 'mübaşir mahkeme salonunda duruşmaya girecek olan kişileri ve tanıkları çağıran hakimin isteklerini yerine getiren ve belgeleri iletmekle görevli olan kimselerdir mübaşirler meslek olarak genel idare hizmetleri sınıfında yer alır aynı zamanda mahkeme dosya düzeninden duruşma günü işlemi olan dosyaları sıralamak ve dosyaya gelecek olan evrakı takipten sorumludur mübaşirler sadece adliyede görev yaparlar adalet bakanlığına bağlı cezaevleri ve benzeri diğer kurum ya da kuruluşlarda çalışamazlar öte yandan duruşmanın gereği gibi işlemesi dosyaların eksiksiz kaydedilmesi ve hakime eksiksiz dosya verilmesi gibi görevleri yürüten mübaşirlerin çok dikkatli ve bilinçli hareket etmeleri gerekir duruşma sırasında gelen tarafları ve tanık olacak kişileri çağırmak duruşma salonuna girişlerini sağlamak salonda duracakları yeri göstermek ve bunlara riayet etmelerini sağlamak mübaşirin esas görevidir duruşma taraf ya da tanık olan kişilerden belge toplayarak hakime vermek ve duruşma yapılan salonda hakimden aldığı direktiflere uygun olarak disiplini sağlamak mübaşirin görevleri arasında yer alır duruşma devam ederken söz söyleyecek olan kişinin sözünü ayakta söylemesini mübaşir sağlar bunun yanı sıra salonda bulunanları da ayağa kalkmaları konusunda uyarır mübaşir yemin verildiği ve kararın açıklandığı esnada duruşma salonunda bulunanları uyması gereken kurallar hakkında uyarır duruşmanın kapalı yapılma kararı alınması halinde salonu boşaltmak ve duruşmanın kapalı yapıldığına dair bilgi levhasını kapıya asmakla da sorumludur duruşma tarihi ileri bir zamana ertelendiyse mübaşir duruşma tarihine dair bilgi kağıdını taraflara verir internet üzerinden bilgilendirme sistemi bulunmayan adliyelerde günlük duruşma listesini görünür şekilde asmak bir diğer görevidir mübaşir mahkemeye ait evrak ve yazıları zimmet defterine kaydederek ilgili makamlara teslim eder ayrıca müzekkere ve tebligatları da ilgili makamlara ulaştırmak üzere posta işlemlerini yapmakla yükümlüdür mahkemeye ait olan ve postaya verilecek evrakları postaya teslim etmek de mübaşirin görevidir mahkeme başkanı ve hakimin uygun gördüğü yazı işleri müdürünün denetimi altında kalem işlerinde çalışması mübaşirin duruşma dışında yaptığı bir diğer görevdir arşive götürülmesi ve arşivden çıkarılması gereken dosyaları düzenleyerek arşivi düzenli tutan mübaşir genel anlamda arşiv işlerinden de sorumludur evrakları düzenli bir şekilde dosyaya takmak da mübaşire ait bir görevdir'),
(3, 'Metin 19', 'kişilerin kan bağı veya sözleşme ile bağlı olduğu ailenin taşıdığı adıdır soyadı kanununun birinci maddesine göre herkes kendi adından başka soyadını taşımaya mecburdur kanunun ikinci maddesinde soyadının nasıl kullanılması gerektiği belirtilmiştir söyleyişte yazıda imzada kendi adı önde soyadı sonda kullanılır ailenin fertlerini diğer ailelerden ayırmaya yarayan soydan soya geçen kelime olan soyadı kendiliğinden kazanılır medeni kanunun ilgili maddesinde çocuk anne ve baba evliyse ailenin soyadını taşır ancak anne önceki evliliğinden dolayı çifte soyadı taşıyorsa çocuk onun bekarlık soyadını taşır hükmü soyadının kendiliğinden nasıl kazanıldığını belirtmiştir buna göre çocuk evlilik birliği içinde doğmuş ise babasının soyadını alacaktır ancak çocuk annenin yeniden evlenmesi halinde annenin bekarlık soyadını alır diğer taraftan nüfus hizmetleri kanunu ve nüfus hizmetlerine ilişkin yönetmelik gereği evlilik birliği dışında doğan çocuk annenin soyadını alır evlenen kadın ise evlilik töreninin bitmesiyle birlikte kocasının soyadını alır ancak kadınlar istemeleri halinde kocalarının soyadlarının önünde önceki soyadlarını kullanabilirler takma ad mahlas olarak bilinen müstear ad kişilerin belirli bir işi yaparken kendi adları yerine kullandıkları addır fatih sultan mehmet tarafından kullanılan avni meşhur olmuş takma adlara örnektir medeni kanunda doğrudan düzenlenmemiş olsa da takma ad kişilik hakkının kapsamına dahil olup medeni kanunun ilgili maddesi gereği kişinin ismi gibi korunur lakap kişilere başkaları tarafından takılan isminin yerine kullanılan veya ismine eklenen addır lakap özü itibarıyla niteleme olup bir veya birkaç kelimeden oluşabilir lakap medeni kanunda düzenlenmemiş ad türlerindendir ancak lakap doktrinde korunmaya değer olarak kabul edilmektedir ayrıca lakabın ad olarak kabul edilmediği durumlarda kişilik hakkını kapsar sayılarak korunması gerektiği ileri sürülmektedir ticaret unvanı bir taciri diğer tacirlerden ayırmaya yarayan addır türk ticaret kanununda tacir ticari işletmesine ilişkin işlemleri ticaret unvanıyla yapmaya mecburdur bu sebeple tacir seçtiği ticaret unvanını ticaret siciline tescil etmeye zorunludur ticaret unvanının medeni kanun ve türk ticaret kanununa göre korunması önemlidir işletme adı tacirlerin ve esnafların kullanmak zorunda oldukları onları diğer işletmelerden ayırmaya yarayan addır işletme adı ticaret unvanı gibi türk ticaret kanunu uyarınca korunması gereken addır'),
(3, 'Metin 20', 'medeni kanun ve dernekler kanununa göre dernekler gerçek veya tüzel asgari yedi kişinin kazanç paylaşma dışında belirli ortak amacı gerçekleştirmek üzere çalışmalarını sürekli olarak birleştirmek amacıyla oluşturdukları tüzel kişi topluluklarıdır derneğin dört temel unsuru vardır dernek asgari yedi gerçek veya tüzel kişiden oluşmaktadır dernek kurulduktan sonra derneğe başkaları katılabilir derneği oluşturan veya derneğe katılan kişilere üye denir üye derneğin ilk unsurudur derneğin ikinci unsuru üyeleri bir araya getiren amaçtır amacı olmayan dernek kurulamaz ayrıca derneğin güttüğü amaç hukuka aykırı olamaz derneğin belirli bir amacı gerçekleştirmesi için belirli bir süre kararlaştırılamaz önemli olan amacın gerçekleşmesidir bu sebeple derneğin üçüncü unsuru sürekliliktir üye ve amaç unsurlarının varlığı bu kişi topluluğunun dernek olarak anılması için yeterli değildir bu kişi topluluğunun tüzel kişilik kazanması için örgütlenmesi ve bağımsız olması gerekmektedir bunun için derneğin kuruluş tüzüğünde derneğin amacı derneğin üyeleri dışında tüzel kişi olduğu açık bir şekilde ifade edilmelidir bu sebeple derneğin son unsuru derneğin tüzel kişiliğe sahip olmasıdır türk hukuk sisteminde derneklerin kuruluşunda tescil sistemi benimsenmiştir bunun içindir ki dernek kurucularının derneğin yerleşim yerinin bulunduğu yerdeki en büyük mülki amirliğe kuruluş bildirimini yapmaları gerekir her derneğin tüzüğünün olması zorunludur derneğin kurucu üyelerinin iradelerine dayanan tüzük dernek için hukuk normu niteliğindedir derneğin tüzüğünde derneğin adı amacı gelirleri üyelik koşulları organları geçici yönetim kurulu gibi zorunlu olan unsurlar yer almalıdır dernek tüzüğünün tüm kurucu üyeler tarafından imzalanması gerekir imzalanan tüzük ile birlikte gerekli diğer belgelerin yerleşim yerinin en büyük mülki amirine teslim edilmesi sonucu dernek tüzel kişilik kazanır mülki amire gönderilen tüzük mülki amir tarafından süresi içinde dosya üzerinden incelenir yapılan inceleme sonunda kanuna aykırılık veya eksiklik tespit edilmezse dernek dernekler kütüğüne kaydedilir ancak tüzükte ve diğer belgelerde eksiklik saptanırsa bu eksikliğin giderilmesi için dernek kurma talebinde bulunanlara makul süre verilir bu sürede eksiklikler tamamlanmaz ya da hukuka aykırılık giderilmezse en büyük mülki amir derneğin feshi konusunda dava açılması için savcılığa bildirimde bulunur yetkili asliye hukuk mahkemesinde derneğin feshi davası açılır'),
(3, 'Metin 21', 'medeni kanuna göre vakıflar gerçek veya tüzel kişilerin yeterli malları belirli ve sürekli amaca özgülemeleriyle oluşan tüzel kişiliğe sahip mal topluluklarıdır tanıma göre vakfın dört temel unsuru vardır öncelikle vakfın belirli ve sürekli amacını gerçekleştirmeye özgülenmiş yeterli mal varlığının olması gerekmektedir dolayısıyla vakfın temel ögesinin mal varlığı olduğu açıktır çünkü vakfı ortaya çıkaracak mal bulunmazsa vakıf olmaz mal varlığının tamamı veya ekonomik değeri olan haklar vakfedilebilir niteliktedir bu sebeple vakfın mal varlığının kapsamına taşınır mallar taşınmaz mallar kıymetli evraklar alacak hakları girebilir vakfın ikinci unsuru vakıf oluşturmadaki amaçtır vakıf belirli ve sürekli amacının bulunması halinde kurulabilir vakfın amaç unsuru manevi veya iktisadi olabilir vakfın amacı vakfı kuran kişinin iradesi sonucu serbestçe belirlenebilir kurulacak vakfın derneklerden farklı olarak birden fazla amacı olabilir ancak vakıfların amacı imkansız hukuka ahlaka milli birliğe milli menfaatlere aykırı olamaz vakfın üçüncü unsuru ise özgülemedir özgüleme bir mal veya malvarlığının devamlı olarak vakfın amacına tahsis edilmesidir başka deyişle özgüleme vakıf için belirlenmiş amaca hizmet edecek malların tüzel kişi meydana getirmek amacıyla ayırt edilmesidir özgüleme ile malların mülkiyeti hemen vakfa geçmez malların mülkiyeti kurulan vakfın mahkemelerce tutulan sicile tescil edilip tüzel kişilik kazanmasıyla vakfa geçer vakfın dördüncü unsuru vakfı kuran kişidir vakıf kuran kişi gerçek veya tüzel kişi olabilir vakıf kuran gerçek kişi olması halinde fiil ehliyetine sahip olması gereklidir dolayısıyla sınırlı ehliyetsiz kişiler kanuni temsilcisinin rızası bulunsa bile vakıf kuramazlar ancak tam ehliyetliler sınırlı ehliyetliler vakıf kurabilirler ayırt etme gücüne sahip sınırlı ehliyetsizler vasiyetname aracılığıyla vakıf kurabilirler vakıf kurmak isteyen kişi medeni kanun gereği vakıf kurma iradesini noterde düzenlenen senet veya ölüme bağlı tasarrufla açıklayabilir vakıf kurma iradesini gösteren belge vakıf senedi olarak adlandırılır türk medeni kanununda vakıf senedinde bulunması gerekli olan unsurlar yer almaktadır vakıf kurma işlemi bittikten sonra vakıf özel sicile kaydedilir sicile kayıt sonrasında vakıf tüzel kişilik kazanmış olur mahkemenin vakıf kuruluşunu onaylaması için vakfın zorunlu organlarının oluşturulmuş olması gerekir medeni kanuna göre vakfın tek zorunlu organı yönetim organıdır'),
(3, 'Metin 22', 'kişilerin herhangi bir eşya üzerinde sahip olduğu herkese karşı ileri sürülebilen mutlak haklara ayni hak denir ayni haklar kişiye eşya üzerinde doğrudan doğruya hakimiyet olanağı sağlar dolayısıyla herkese karşı ileri sürülebilir ayni hak sahibi bu hakkından doğan yetkilerini eşya üzerinde doğrudan doğruya kendisi kullanmaya yetkilidir kişinin kullanım haklarını toplumdaki herkes tanımak ve uymak zorundadır ayni hakkın diğer haklardan farkını görmek için alacak hakkı örnek olarak verilebilir alacak hakkı mutlak haklardan olmayıp kişinin başkalarına karşı sahip olduğu şahsi haklardandır alacak hakkının sahibi yalnızca borçludan hakkını tanımasını ve gerektiği şekilde davranmasını isteyebilir şahsi haklardan olan alacak hakkından kaynaklanan borcu hak sahibine tüm toplum ödemek zorunda değildir borcun ifasıyla sadece borçlu kişi yükümlüdür eşya üzerindeki ayni hak sahibi bu hakkının ve yetkilerinin tanınmasını toplumdaki herkesten isteme hakkına sahiptir toplumdaki tüm insanlar hakkın sahibi bireyin eşya üzerindeki hakimiyetini onunla ilgili tüm yetkilerini tanımak ve hareket etmek zorundadır burada gözden kaçırılmaması gereken önemli nokta alacak hakkını sadece borçlu ihlal edebilirken ayni hakkı toplumdaki tüm bireyler ihlal edebilir yalnızca borçlu kişi veya kişilerin alacaklıya borcunu ödememesi hak sahibinin hakkının ihlal edileceği anlamına gelir toplumdaki diğer bireylerin bu borcu alacaklıya ödememeleri hak ihlali teşkil etmez fakat eşya üzerinde ayni hak sahibi bireyin eşyalarına zarar verecek olursa veya onun eşyasını kullanmasını kısıtlamaya kalkışırsa toplumdaki tüm bireyler bu kişinin hakkını ihlal etmiş olacaktır çünkü eşya üzerindeki ayni haklar mutlak haklardır ayni hakların üç temel unsuru vardır birincisi eşya ikincisi sahip olunan eşya üzerinde hak sahibinin doğrudan doğruya hakimiyetinin bulunması üçüncüsü herkese karşı ileri sürülebilmesidir ayni haklar farklı yönlerden değerlendirildiğinde farklı türlere ayrılabilir hakları ayni hakların hak sahibine sağladığı yetkiler yönünden ayrıca hak sahibinin belirlenme biçimi yönünden incelemek daha doğru olacaktır eşya üzerinde sahibine sağladığı yetkiler yönünden ayni haklar iki gruba ayrılmaktadır mülkiyet hakkı ayni haklar arasında kişiye eşya üzerinde en geniş yetkiyi sağlayan haklardır sınırlı ayni haklar kişiye eşya üzerinde mülkiyet hakkının içindeki bazı yetkiler farklı biçimlerde ayrılarak bunların yeni hak olarak tanımlanmasıyla oluşur'),
(3, 'Metin 23', 'eşya kavramı hukuk dilinde günlük dilde kullanılan eşya kavramından biraz farklılık gösterir günlük dildeki kavram sıklıkla varlıkların fiziksel özelliklerini ifade etmek için kullanılırken hukukta varlıklara fiziksel özelliklerinin yanında işlevsel bir anlam da yüklemektedir hukukta herhangi bir varlığın eşya olarak kabul edilebilmesi için onun sadece fiziki yapısına bakılmaz aynı zamanda ekonomik toplumsal ahlaki işlevine bakılır örneğin tek mısır tanesi hayvanın tek tüyü günlük hayatta fiziksel olarak eşya gibi değerlendirilebilir fakat hukuken bunlar tek başına eşya olarak kabul edilmemektedir çünkü tek buğday tanesinin veya tek hayvan tüyünün insanın herhangi bir ihtiyacını karşılayacak büyüklüğe ekonomik değere veya miktara sahip olduğu iddia edilemez bunların üzerinde bir sanatçının çok küçük boyutlarda işlediği yazı veya resim mevcutsa bu varlıklar hukuken eşya olarak kabul edilecektir bu durumda varlıklarda işlevsel bir farklılığın ortaya çıktığı görülmektedir bu eşyaların sahibi kişilerin bunların sanat eserine dönüştüğünü ekonomik değerlerinin arttığını veya başka eşyalarla değiş tokuş yapılabileceğini iddia edebilecekleri tahmin edilebilir türk medeni kanununda sadece fiziki varlığı olan şeylerin eşya olarak kabul edileceği belirtilmiştir hukuk fiziki varlığı bulunmayan ama ekonomik değeri olan şeyleri de bazı hallerde eşya gibi kabul etmektedir örneğin bazı hakların eşya gibi sayıldığı ve bunların da eşyalarda olduğu gibi satış veya devir konusu olabilmesi mümkündür türk medeni kanununda bir varlığın eşya sayılması için hukuki iradeye elverişli olması gerektiği belirtilmiştir burada kastedilen varlığın yasaklı olmaması gerektiği ve bireysel mülkiyete alınamayacak sınırları olmayan varlıkların eşya olarak sayılamayacağıdır örneğin hukuken satışı yasaklanmış herhangi bir madde ülkenin doğal kaynakları gökyüzü gezegenler eşya hükmünde kabul edilemez bunlar herhangi bir şekilde mülkiyete konu edilemez eşyaların kişisel olmaması kuralına göre insanların vücudu organları ve cesedi eşya olarak kabul edilemez veya bunlar üzerinde herhangi bir hak iddia edilemez insan vücudunun doğal bir parçası haline gelmiş takma organlar da eşya olarak kabul edilemez fakat takma dişe benzer nitelikte vücuttan kolaylıkla çıkarılıp el değiştirebilecek olan protez parçalar insan vücudunun parçası olarak görülmemekte ve eşya olarak sayılmaktadır eşya farklı ölçütler içinde değerlendirilip farklı türlerde ele alınmaktadır'),
(3, 'Metin 24', 'toplum düzeninin ayakta kalması ve sosyal barışın korunması için kişilerin sahip olduğu hakları hukuk düzeni korumalıdır hukukun tek işlevi kişilerin sahip olduğu hakları düzenlemek değildir hukuk düzeninin bir yandan kişilerin haklarını tanıması diğer yandan kendiliğinden hak almayı yasaklaması sonucu bireysel hakların korunması devletin sorumluluğu altına girmiştir devlet bu sorumluluğu nedeniyle mahkemeler kurmuş ve kişilere dava hakkı tanımıştır dava hakkı bir kişinin hak elde etmek veya sahip olduğu hakkın korunmasını temin amacıyla devletin tarafsız ve bağımsız mahkemelerine başvurma hakkını ifade etmektedir kişinin dava hakkını kullanarak mahkemeye başvurması ve devletin hak dağıtmada harekete geçmesini istemesine dava denilmektedir dava medeni yargılama hukukunda taraf sistemi üzerine kurulmuştur davayı açan kişiye davacı kendisine karşı dava açılan kişiye ise davalı denir karşılıklı uyuşmazlığın bulunduğu çekişmeli bir yargıda hakim davalı ve davacı rolünde olan tarafların olup olmadığını göz önünde bulundurur çünkü çekişmeli yargıda davacı ve davalının olması dava şartlarından biridir dava şartları ise davanın açılması ve dava konusu anlaşmazlık hakkında araştırma yapılıp esas hakkında karar verilmesi için gerekli olan şartlardır tarafın belirtilmesi dava şartı olduğu için dava açılırken davalı tarafının gösterilmesi zorunludur dava açılırken davalı taraf gösterilmemiş ise dava dilekçesi reddedilir çünkü mahkemenin belirtilmemiş tarafı araştırma yükümlülüğü yoktur diğer taraftan dava açılırken dava dilekçesinde birden fazla davalı veya birden fazla davacı gösterilebilir mahkemede taraflar eşit hak ve yetkilere sahiptir buna medeni yargılama hukukunda silahların eşitliği denir bu eşitlik davalı ve davacının mutlak anlamdaki eşitliğini değil şekli anlamdaki eşitliğini ifade eder çünkü davada tarafların üstlendikleri roller nedeniyle birçok farklılık bulunur ancak hakim tarafları dinleyerek sonuca ulaşacaktır çekişmeli davada dava şartı olan davalının ve davacının bulunması çekişmesiz yargı için söz konusu değildir medeni yargılama hukukunun bir alt dalı olan çekişmesiz yargı karşılıklı bir uyuşmazlığın olmadığı ve tarafların yer almadığı yargı türüdür bu yargı türünde taraf kavramı yerine ilgili kavramı mevcuttur çekişmesiz yargılamada birden fazla ilgili bulunabilir hatta bu ilgililer farklı iddialar ve taleplerde bulunabilir bu sebeple çekişmesiz yargıda görüş birliği olup olmaması önemli değildir'),
(3, 'Metin 25', 'görgü bir toplum içinde var olan saygı ve incelik kuralları olarak ifade edilmektedir görgülü olmak aynı zamanda nezaket kavramını da içermektedir nezaket başkalarına karşı saygıyla incelikle davranma ve nazikliktir nezaket kavramının içinde her zaman başkalarını düşünerek hareket etmek başkalarına iyilik edebilmek için gayret göstermek ve tüm bunları samimiyetle yapmak duyguları gizlidir nazik davranışlar olumsuz tavırlı insanları bile mıknatıs gibi kendine çekerek olumluya dönüştürebilir nezaket ve görgü kurallarını uygulama estetiğine ise zarafet denir başka ifadeyle zarafet nezaket ve görgü kurallarını kişinin bakışı duruşu ve konuşma üslubuyla incelik ve güzellikle yansıtabilme yeteneği olarak tanımlanabilir her toplumun sosyal yaşamı saygı görgü ve nezaket kurallarıyla düzenlenmiştir görgü ve nezaket kuralları sosyal yaşamda herkesin kişiliğine ve yaşama hakkına saygı göstermeyi gerektirir dolayısıyla söz konusu bu kurallar yaşamı zorlaştırmaz tam tersine kolaylaştırır çünkü kuralları uygulayan kişi toplum içinde nazik bir insan olarak tanınır sevgi saygı görür itibar kazanır sosyal yaşamda görgü ve nezaket kurallarına uymanın yasal zorunluluğu veya uymama sonucu yasal yaptırımı yoktur ancak kurallara uymayanlar toplum tarafından dışlanırlar kurallara uymak sosyal hayatta başkalarıyla yaşamanın ve sosyalleşmenin doğal bir gereğidir iletişimde güzel konuşma her zaman olumlu ve yapıcıdır konuşurken sözlerin içeriği kadar söyleniş şekline de dikkat etmek etkili dinleme becerilerini kullanmak nazik ve görgülü olmanın önemli basamağıdır söz verilmeden ve gereğinden fazla konuşmamak gerekir yanlışlıkla birinin sözü kesildiğinde özür dilenmelidir karşınızdaki kişi veya kişilerle yumuşak ve samimi bir ses tonuyla saygılı ifade ve üslupla konuşmalı argo kelimeler kullanmak ve yüksek sesle konuşmaktan kaçınılmalıdır konuşma sırasında kişinin sürekli kendisinden söz etmesi doğru değildir akıl verici tarzda konuşmaktan kaçınmalı konuşurken anladınız mı diye sorulmamalı anlatabildim mi şeklinde sorulmalıdır kişi görüş ve düşüncesine aykırı bir şey söylendiğinde hemen tepki gösterilmemeli karşı görüş ve düşünceler saygı ve hoşgörü ile karşılanmalıdır çünkü konuşma ve tartışmanın ilk kuralı başka görüş ve düşüncelere saygılı olmaktır konuşan iki kişinin yanına gidilmemeli gitmek gerekliyse de izin alınmalıdır konuşmada karşıdaki kişi ya da kişilerin anlamayacağı teknik terimler ve yabancı kelimeler kullanılmamalıdır'),
(3, 'Metin 26', 'medeni hukuktaki hak ehliyetinin medeni usul hukukundaki karşılığı olan taraf ehliyeti mahkemelerde davalı veya davacı olarak bulunabilme ehliyetidir kanun koyucu medeni kanunda maddi haklardan yararlanma ehliyetine sahip olan davada taraf ehliyetine de sahiptir diyerek kimlerin taraf ehliyetine sahip olduğunu düzenlemiştir buna göre taraf ehliyetine sahip olabilmenin koşulu hak ehliyetine sahip olmaktır bütün gerçek ve tüzel kişiler hak ehliyetine sahip oldukları için ayrıca taraf ehliyetine sahiptirler taraf ehliyeti davanın olmazsa olmaz koşuludur dolayısıyla taraf ehliyetine sahip olmayan kimseye dava açılmışsa dava reddedilir taraf ehliyetine sahip olmayan birine dava açılmış ve mahkeme tarafından hüküm verilmiş olması halinde verilen hüküm hukuki sonuç doğurmaz gerçek kişilerin taraf ehliyeti sağ olarak tamamıyla doğmalarıyla başlar ancak cenin annesinin rahmine düştüğü andan itibaren sağ doğmak koşuluyla taraf ehliyetine sahiptir herhangi davaya ceninin taraf olması gerekliyse cenine kayyum atanır kayyum ceninin yasal temsilcisi olarak dava açabilir kayyumun açmış olduğu dava devam ederken temsilcisi bulunduğu çocuk sağ doğmazsa kayyumun taraf ehliyetinin geçerliliği sona ereceğinden açılmış dava reddedilir ancak çocuk doğmadan dava sonuçlanıp çocuk ölü doğarsa mahkemenin kararı hükümsüz sayılır gerçek kişilerin taraf ehliyetleri ölümle birlikte sona erer davanın açıldığı tarihten önce ölmüş kişiye dava açılamaz ölmüş kişiye dava açılmış ise mahkeme taraf ehliyetinin olmaması nedeniyle davayı reddeder mahkeme davalının öldüğünü bilmeden karar verdiyse verilen karar hukuken geçersizdir ancak mirasçıların malvarlığının etkilendiği bir davada davalının öldüğü bilinmeden dava açılmış olabilir bu tür davalarda yargılama sırasında davalının öldüğü tespit edilirse dava hemen düşmez nitekim davaya mirasçılarla devam edilebilir dava devam ederken davacı veya davalı taraflardan birinin ölümü durumunda dava konusuz kalmaz dava sırasında taraflardan biri ölürse mirasçıların mirası kabul etmelerine veya reddetmelerine göre hareket edilir bu tarz durumlarda dava mirası ret için kanunda öngörülen süreler geçinceye kadar ertelenir ancak davaya devam etmek isteyen taraf davanın devam etmesini isterse mahkeme öngörülen sürenin geçmesini beklemeden davanın takip edilmesi için kayyum atanmasına karar verebilir gerçek kişiler dışında tüzel kişiler de hak ehliyetine sahip olmaları nedeniyle taraf ehliyetine de sahiptirler'),
(3, 'Metin 27', 'dava ehliyeti medeni hukuktaki fiil ehliyetinin medeni usul hukukundaki karşılığıdır dolayısıyla medeni hakları kullanma ehliyetine sahip bütün gerçek ve tüzel kişilerin dava ehliyeti vardır ayırt etme gücüne sahip ergin bulunan ve kısıtlı olmayan herkes dava ehliyetine sahiptir ancak ayırt etme gücüne sahip küçüklerle kısıtlılar kural olarak dava ehliyetine sahip değildir ayrıca ayırt etme gücüne sahip olmayanların fiil ehliyetleri bulunmaz fiil ehliyeti bulunmayan kişilerin dava ehliyetleri yoktur dava ehliyeti bulunmayan kişilerse davada yasal temsilcileri tarafından temsil edilirler kişilerin bizzat dava açması veya yetkili kıldığı temsilciyle davayı takip edebilmesi için dava ehliyetine sahip olmaları gerekir buradan anlaşılacağı üzere dava ehliyeti tarafa ilişkin dava şartıdır ancak dava ehliyeti olmayan kişilerin dava açması veya dava ehliyeti olmayan kişilere dava açılması halinde dava hemen reddedilmez dava ehliyeti olmayan kişiler tarafından dava açılmışsa mahkeme söz konusu tarafın yasal temsilcilerine tebligat gönderir tebligatta yasal temsilcilere davaya devam edilip edilmeyeceğine yönelik karar verilmek üzere uygun bir süre tanınır yasal temsilciler verilen sürede davaya onay verirlerse davaya yasal temsilciler tarafından devam edilir ancak yasal temsilciler kendilerine verilen süre içerisinde cevap vermez veya davaya onay vermezlerse dava reddedilir diğer taraftan dava ehliyeti olmayan birine dava açılmışsa dava dilekçesi davalının yasal temsilcisine gönderilir yasal temsilci bulunmuyorsa davalıya mahkeme tarafından yasal temsilci atanır gerçek kişiler gibi tüzel kişiler de dava ehliyetine sahiptir hem özel hukuk tüzel kişilerinin hem de kamu tüzel kişilerinin dava ehliyetleri vardır tüzel kişiler davada kendilerini temsile yetkili organlar aracılığıyla temsil edilirler ancak verilen hüküm sadece tüzel kişinin temsil organını değil tüzel kişinin tamamını etkiler dava dilekçesinde davacı ve davalı taraflar dava ehliyetine sahipseler dava içerisindeki iş ve işlemleri yapabilirler tarafların davaları sonuçlandırıp kendileri için hüküm almaları ancak dava takip yetkisine sahip olmalarıyla mümkündür dolayısıyla davanın geçerli şekilde açılıp incelenerek sonuca bağlanmasında davayı açanın dava takip yetkisine sahip olması gerekir çünkü dava takip yetkisi dava konusu hukuki ilişkinin tarafı olmaktır dava konusu hak ya da hukuki ilişkinin tarafı olmaksa verilecek hükümden doğrudan etkilenmek demektir'),
(3, 'Metin 28', 'yasal temsil dava ehliyeti olmayan kişiler için öngörülmüş temsildir ayrıca tüzel kişilerin kendilerini temsile yetkili organı aracılığıyla temsil edilmesi yasal temsil kapsamında değerlendirilir yasal temsilin hangi hallerde mümkün olduğu içeriği ve sona ermesi kanunla belirlenir yasal temsilci temsil ettiği kişi adına hareket eder bu sebeple davanın açılıp açılmayacağına tek başına karar veremez örneğin davanın açılması için izin gerekliyse yasal temsilci izin belgelerini mahkemeye vererek dava açabilir gerekli olan belgelerin mahkemeye verilmemesi durumunda dava açılmamış sayılır türk hukuk sisteminde avukatla temsil zorunlu değildir bu nedenle dava ehliyeti bulunanlar kendi davasını açıp takip edebilir veya atadığı bir temsilci aracılığıyla davasını açabilir ve takip edebilir bu tür durumlarda iradi temsil söz konusu olur iradi temsil tarafların iradelerine dayanan temsildir davanın taraflarından herhangi birisi kendisini temsil edecek kişiye vekalet vererek davayı takip etmek isteyebilir ancak vekalet verilecek kişiler yalnızca baroya kayıtlı avukatlardır kişiler noterde yapacakları işlemle baroya kayıtlı avukatlar arasından bir veya birkaçına vekalet verebilir vekalet temsil yetkisi bakımından genel vekalet ve özel vekalet olmak üzere ikiye ayrılır genel vekalet davada gerekli olan işlemlerin tamamını yapabilme yetkisidir ancak genel vekaleti olan kişilerin vekalet verenin izni olmadan yapamayacağı işlemler de bulunmaktadır hukuk muhakemeleri kanununa göre temsilcilerin sulh olma davanın tamamını ıslah etme hakimi reddetme yemin teklif etme yemin kabul etme gibi bazı işlemleri yapabilmesi açık yetki verilmesiyle mümkündür belirli bir veya birkaç işlemin temsilci aracılığıyla yapılmasına olanak veren vekalet türüne ise özel vekalet denir özel vekaletname olarak düzenlenmiş vekaletnamede temsilcinin yapabileceği işlemler yer aldığı için temsilci bu işlemlerin dışında işlem yapamaz dava devam ederken taraflardan birisinin kendisine yardım etmek üzere üçüncü kişiye davayı haber vermesine davanın ihbarı denir davanın ihbarı genel itibarıyla davaya müdahale değildir nitekim davaya müdahale üçüncü kişinin kendi isteğiyle gerçekleşir mecburi dava arkadaşlığının mevcut olduğu durumlarda davanın ihbarı söz konusu değildir davanın ihbarının ilk koşulu ihbar yapılacak kişinin davanın tarafı olmayan üçüncü kişi olmasıdır ihbarda bulunan tarafın ihbarda bulunmak için herhangi bir makamdan izin almasına gerek yoktur'),
(3, 'Metin 29', 'mesleği gereği günün büyük bir kısmını bilgisayar kullanarak geçiren kişilerin bilinçsiz ve tekniğine uygun olmayan klavye kullanımları sonucu hareketsiz kalmaları nedeniyle vücudun çeşitli yerlerinde meydana gelen hastalıkların yanı sıra el ve kollarda hastalık oluşma riski oldukça yüksek olup bu durum iş verimini olumsuz yönde etkilemektedir uzun süreli durumlarda el kaslarında güçsüzlük ve erimeler oluşabilir bu durum genellikle on parmak tekniğini kullanmayan veya klavyeyi hatalı tekniklerle kullanan kişilerde görülür yazarken bilekleri klavyeye veya masaya değdirmek parmakları aşırı yukarı kaldırarak yazmak ve klavyede sert vuruşlar yapmak başlıca temel yazım hatalarıdır klavye kullanım teknikleri hatalı bir şekilde yazı çalışması yapanlarda birtakım sağlık problemleri oluşabilir özellikle sabit pozisyonda uzun süre kalınması yazı yazarken on parmak tekniğini kullanmayan kişilerin yazıyı görmek için boynunu eğmesi ve sürekli yazdığı yerle klavyeye bakması boyun fıtığı olma riskini büyük oranda artırmaktadır yanlış tekniklerle yazı yazarken el kaslarına aşırı yük bindiğinden bu durum eldeki tendon kaslarının kalınlaşmasına ve buna bağlı olarak sinirler üzerinde baskı oluşmasına neden olmaktadır el ve bilek çevresinin aşırı kullanılması sonucu ellerde özellikle geceleri belirgin uyuşma şikayetine neden olarak günlük yaşantımızı olumsuz yönde etkilemektedir on parmak tekniğine konu olan klavye performansıdır klavye performansı ise konum ritim sürat ve hatasızlık olmak üzere dört bölümden oluşmaktadır tekniğin öğretimindeki amaç birkaç parmakla yazı yazmak yerine on parmakla etkili hatasız ve süratli şekilde yazı yazmaktır metodu öğrenenler genelde klavyede süratli ve hatasız yazan kişilerdir on parmak metodunu kullanan birisi gözleri kapalı dahi olsa yazarken hata yaptığını anlayarak düşünmeden silme tuşuna basarak hatasını anında düzeltebilir temel klavye kullanım tekniğinde sandalyeye otururken sırtınız dik vücudunuzun yukarı kısmı hafif öne doğru eğimli olmalıdır yazılacak yazı rahatlıkla okunabilecek şekilde masanın üzerinde konumlandırılır ve dirsekler vücuda yakın tutulur dirsekleriniz gövdenizin tam yanında olmalıdır uygun uzaklıkta oturulması durumunda dirsekleriniz omuzdan inen dikey hattın hizasında dik açıda olur bilekler klavyenin alt kısmına veya masaya dokunmayacak şekilde havada tutulur parmaklar yuvarlak bir cismi tutar gibi kıvrık tutulur tuşlara parmak uçlarının çok az değdiği hissedilir'),
(3, 'Metin 30', 'tahkikat aşaması delillerin incelenmesi ve bunlardan elde edilen bilgiler ışığında mahkemede oluşacak kanaatle davanın tarafları arasında çekişmeli olan olguların gerçek olup olmadığının tespit edildiği dava aşamasıdır en uzun yargılama safhasıdır bu aşamanın sonunda mevcut ve doğru olduğu mahkemece takdir edilen olgulara sübut bulmuş olgular denir ispatla sübut bulanlar ile taraflar arasında çekişmesiz olduğu için ispat faaliyetine gerek olmayan uyuşmazlık çözümünde önemli olgular tahkikat aşaması sonunda bir araya gelmiş olur hakim tarafların iddia ve savunmaları sonucu toplanan delilleri dikkatle inceler bu inceleme sonucu duruşmada hazır bulunan taraflara tahkikatın tümü hakkında beyanda bulunmaları için söz verir taraflar mahkemeye toplanan ve incelenen deliller üzerinden sübut bulan ya da bulmayan olgularla ilgili görüşlerini sunabilir mahkeme tahkikatın genişletilmesini gerektiren bir durum kalmadığını görürse tahkikatı bitirerek bu durumu taraflara bildirir tahkikat sonrası mahkeme sözlü yargılama ve hüküm için tayin edilen gün ve saatte mahkemede hazır bulunmaları için tarafları davet eder davetiyelerde taraflara belirlenen gün ve saatte mahkeme salonunda hazır bulunmazlarsa yokluklarında hüküm verileceği bildirilir sözlü yargılamanın ayrı bir oturumda yapılması esastır sözlü yargılamada hakim her iki tarafa da mevcut olgular karşısında iddia ve savunmanın ileri sürdüğü taleplere ilişkin diyeceklerini sözlü şekilde sunmaları için söz vermesi gereklidir tarafların beyanları alındıktan sonra hakim aynı oturumda nihai kararını verir ve nihai kararını sözlü olarak açıklayıp tutanağa geçirir hükmün hakim tarafından sözlü şekilde tarafların yüzüne karşı okunmasına hükmün tefhimi denir tefhim ile tutanağa geçirilen karara ise kısa karar denir hükmün tefhimini duruşmada bulunanlar ayakta dinler sözlü yargılamada açıklanan kısa karar çoğunlukla gerekçeyi ihtiva etmez bunun sebebi hükmün bütün unsurlarıyla yazılmasının zorluğudur ancak hüküm sonucunun tefhim edildiği hallerde gerekçeli kararın bir ay içinde yazılması gerekir iddia ve savunma hakkındaki nihai görüşünü hakim yargılama sonunda karar olarak açıklar ilk derece mahkemesinde yargılama sona erdiğinden hakimin bu kararına nihai karar denir mahkeme tarafından nihai karar bir ay içinde yazılır yazılacak hükmün hangi konuları içermesi gerektiği hukuk muhakemeleri kanununun ilgili maddesinde düzenlenmiştir kararı da hükmü veren hakimin yazdırması esastır');
